<h2>Produtos</h2><form class='row g-2 mb-3'><div class='col-md-3'><input name='q' class='form-control' placeholder='Buscar por nome'></div><div class='col-md-3'><select name='category_id' class='form-select'><option value=''>Todas categorias</option><?php foreach($categories as $c): ?><option value='<?= $c['id'] ?>'><?= e($c['name']) ?></option><?php endforeach; ?></select></div><div class='col-md-2'><button class='btn btn-outline-secondary'>Filtrar</button></div></form><form method='post' action='<?= base_url('/products') ?>' class='row g-2 mb-3'><?= csrf_field() ?><div class='col-md-2'><select name='category_id' class='form-select' required><?php foreach($categories as $c): ?><option value='<?= $c['id'] ?>'><?= e($c['name']) ?></option><?php endforeach; ?></select></div><div class='col-md-2'><input name='name' class='form-control' placeholder='Nome' required></div><div class='col-md-2'><input name='price' class='form-control' placeholder='Preço' required></div><div class='col-md-2'><input name='avg_prep_time' class='form-control' placeholder='Preparo (min)'></div><div class='col-md-2'><input name='image' class='form-control' placeholder='URL imagem'></div><div class='col-md-2'><button class='btn btn-success w-100'>Salvar</button></div><div class='col-12'><textarea name='description' class='form-control' placeholder='Descrição'></textarea></div></form><table class='table'><tr><th>Nome</th><th>Preço</th><th>Status</th></tr><?php foreach($items as $i): ?><tr><td><?= e($i['name']) ?></td><td><?= money_br($i['price']) ?></td><td><?= $i['status']?'Ativo':'Inativo' ?></td></tr><?php endforeach; ?></table>
